#!/usr/bin/env python3
import base64, os, sys
if not os.path.isfile("App.js"): sys.exit("Run from BatKnock root")

with open("ThemeContext.js", "wb") as f:
    f.write(base64.b64decode(""))
print("OK ThemeContext.js")

with open("App.js", "wb") as f:
    f.write(base64.b64decode(""))
print("OK App.js")

os.makedirs("screens", exist_ok=True)
with open("screens/HomeScreen.js", "wb") as f:
    f.write(base64.b64decode(""))
print("OK screens/HomeScreen.js")

print()
print("Run: npx expo start --clear --lan")
print()
print("What changed:")
print("  - Light mode accent: sky blue #60a5fa (was dark blue #2563eb)")
print("  - Light mode header: lighter #4899e8")
print("  - Clear/glass theme added: tap Settings > Clear")
print("  - SafeAreaProvider active in App.js")
print("  - All screens use safe-area-context SafeAreaView")
